import React, { useEffect, useState } from "react";
import { Link } from "react-scroll";
import { Menu, X } from "lucide-react";
import { useNavigate, useLocation } from "react-router-dom";
import { onAuthStateChanged, signOut } from "firebase/auth";
import { auth } from "../../config/firebase";
import logo from "../../assets/logo.png";

function Navbar() {
  const navigate = useNavigate();
  const location = useLocation();

  const [log, setLog] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);

  useEffect(() => {
    const unsub = onAuthStateChanged(auth, (user) => {
      setLog(!!user);
    });
    return () => unsub();
  }, []);

  const logout = () => {
    signOut(auth);
    navigate("/login");
  };

  const links = [
    { id: "home", label: "Home" },
    { id: "about", label: "About" },
    { id: "services", label: "Services" },
    { id: "projects", label: "Projects" },
    { id: "testimonials", label: "Testimonials" },
    { id: "contact", label: "Contact" },
  ];

  const isAuthPage =
    location.pathname === "/login" || location.pathname === "/signup";

  return (
    <>
      {/* NAVBAR */}
      <nav className="fixed top-0 left-0 w-full z-[9999] bg-black backdrop-blur-lg border-b border-yellow-500/30">

        <div className="max-w-7xl mx-auto px-4 md:px-10 h-16 flex items-center justify-between">

          {/* LOGO */}
          <div
            className="flex items-center gap-2 cursor-pointer"
            onClick={() => navigate("/")}
          >
            <img src={logo} alt="logo" className="w-9 h-9 object-contain" />
            <h1 className="text-yellow-400 text-sm md:text-lg font-bold">
              Sri Siva Sakthi Builders
            </h1>
          </div>

          {!isAuthPage && (
            <>
              {/* DESKTOP MENU */}
              <ul className="hidden md:flex items-center gap-8 text-sm text-gray-300">

                {links.map((item) => (
                  <li key={item.id} className="relative group">
                    <Link
                      to={item.id}
                      smooth
                      duration={500}
                      offset={0}
                      className="cursor-pointer pb-2 hover:text-yellow-400 transition"
                    >
                      {item.label}
                    </Link>

                    {/* 🔥 LOADING UNDERLINE */}
                    <span className="absolute left-0 top-6 h-[2px] w-0 bg-yellow-400 group-hover:w-full transition-all duration-500"></span>
                  </li>
                ))}

              </ul>

              {/* RIGHT SIDE */}
              <div className="hidden md:flex items-center gap-4">

                <Link
                  to="contact"
                  smooth
                  duration={500}
                  offset={0}
                  className="px-5 py-2 bg-yellow-500 text-black font-semibold rounded-lg hover:bg-yellow-400 transition"
                >
                  Get a Quote
                </Link>

                {log ? (
                  <button
                    onClick={logout}
                    className="px-4 py-2 border border-yellow-500 text-yellow-400 rounded-lg hover:bg-yellow-500 hover:text-black transition"
                  >
                    Logout
                  </button>
                ) : (
                  <button
                    onClick={() => navigate("/login")}
                    className="px-4 py-2 border border-yellow-500 text-yellow-400 rounded-lg hover:bg-yellow-500 hover:text-black transition"
                  >
                    Login
                  </button>
                )}
              </div>

              {/* MOBILE ICON */}
              <button
                onClick={() => setMenuOpen(true)}
                className="md:hidden text-yellow-400"
              >
                <Menu size={28} />
              </button>
            </>
          )}
        </div>
      </nav>

      {/* MOBILE MENU */}
      {!isAuthPage && (
        <div
          className={`fixed top-0 right-0 h-full w-[75%] bg-black/95 backdrop-blur-lg z-[9999] 
          transform transition-all duration-500 ${
            menuOpen ? "translate-x-0" : "translate-x-full"
          }`}
        >
          {/* HEADER */}
          <div className="flex justify-between items-center p-5 border-b border-yellow-500">
            <h2 className="text-yellow-400 font-bold">Menu</h2>
            <X
              className="text-yellow-400 cursor-pointer"
              onClick={() => setMenuOpen(false)}
            />
          </div>

          {/* LINKS */}
          <ul className="flex flex-col gap-3 p-6">
            {links.map((item) => (
              <Link
                key={item.id}
                to={item.id}
                smooth
                duration={500}
                offset={0}
                onClick={() => setMenuOpen(false)}
                className="px-4 py-3 rounded-lg text-gray-300 hover:bg-yellow-500/10 hover:text-yellow-400 transition-all duration-300"
              >
                {item.label}
              </Link>
            ))}
          </ul>

          {/* CTA + AUTH */}
          <div className="px-6 mt-4 flex flex-col gap-4">

            <Link
              to="contact"
              smooth
              duration={500}
              offset={0}
              onClick={() => setMenuOpen(false)}
              className="block text-center py-3 bg-yellow-500 text-black font-semibold rounded-lg hover:bg-yellow-400 transition"
            >
              Get a Quote
            </Link>

            {log ? (
              <button
                onClick={logout}
                className="border border-yellow-500 text-yellow-400 py-3 rounded-lg hover:bg-yellow-500 hover:text-black transition"
              >
                Logout
              </button>
            ) : (
              <button
                onClick={() => navigate("/login")}
                className="border border-yellow-500 text-yellow-400 py-3 rounded-lg hover:bg-yellow-500 hover:text-black transition"
              >
                Login
              </button>
            )}

          </div>
        </div>
      )}
    </>
  );
}

export default Navbar;